 24→    /// For OpenRouter Anthropic models, inject `cache_control` breakpoints
 25→    /// on the system message and the last user message to enable prompt
 26→    /// caching passthrough to Anthropic.
 27→    pub(super) fn apply_openrouter_cache_control(&self, messages: &mut [serde_json::Value]) {
 28→        if !self.is_openrouter_anthropic()
 29→            || matches!(self.cache_retention, moltis_config::CacheRetention::None)
 30→        {
 31→            return;
 32→        }
 33→
 34→        let cache_control = serde_json::json!({ "type": "ephemeral" });
 35→
 36→        // Add cache_control to the system message content.
 37→        for msg in messages.iter_mut() {
 38→            if msg.get("role").and_then(serde_json::Value::as_str) != Some("system") {
 39→                continue;
 40→            }
 41→            match msg.get_mut("content") {
 42→                Some(content) if content.is_string() => {
 43→                    let text = content.as_str().unwrap_or_default().to_string();
 44→                    msg["content"] = serde_json::json!([{
 45→                        "type": "text",
 46→                        "text": text,
 47→                        "cache_control": cache_control
 48→                    }]);
 49→                },
 50→                Some(content) if content.is_array() => {
 51→                    if let Some(last) = content.as_array_mut().and_then(|a| a.last_mut()) {
 52→                        last["cache_control"] = cache_control.clone();
 53→                    }
 54→                },
 55→                _ => {},
 56→            }
 57→            break;
 58→        }
 59→
 60→        // Add cache_control to the last user message.
 61→        if let Some(last_user) = messages
 62→            .iter_mut()
 63→            .rev()
 64→            .find(|m| m.get("role").and_then(serde_json::Value::as_str) == Some("user"))
 65→        {
 66→            match last_user.get_mut("content") {
 67→                Some(content) if content.is_string() => {
 68→                    let text = content.as_str().unwrap_or_default().to_string();
 69→                    last_user["content"] = serde_json::json!([{
 70→                        "type": "text",
 71→                        "text": text,
 72→                        "cache_control": cache_control
 73→                    }]);
 74→                },
 75→                Some(content) if content.is_array() => {
 76→                    if let Some(last) = content.as_array_mut().and_then(|a| a.last_mut()) {
 77→                        last["cache_control"] = cache_control;
 78→                    }
 79→                },
 80→                _ => {},
 81→            }
 82→        }
 83→    }
