850→                }
851→            }
852→            // Some providers need an explicit model before they can answer;
853→            // keep discovery off there when no model is configured.
854→            // OpenRouter supports `/models`, so we discover dynamically.
855→            let skip_discovery = def.models.is_empty()
856→                && preferred.is_empty()
857→                && !def.local_only
858→                && (def.config_name == "venice" || cfg!(test));
