860→            // /models endpoint (e.g. MiniMax) skip live fetch unless the user
861→            // explicitly opted in via `fetch_models = true` in config.
862→            let user_opted_in = config
863→                .get(def.config_name)
864→                .is_some_and(|entry| entry.fetch_models);
865→            let try_fetch = def.supports_model_discovery || user_opted_in;
866→            let static_catalog =
867→                || -> Vec<DiscoveredModel> { catalog_to_discovered(def.models, 2) };
