871→                    match prefetched.get(def.config_name) {
872→                        Some(models) => models.clone(),
873→                        None => static_catalog(),
874→                    }
875→                } else if !def.supports_model_discovery && !def.models.is_empty() {
876→                    // Provider has no /models endpoint — use the static catalog.
877→                    static_catalog()
878→                } else {
879→                    Vec::new()
880→                };
881→            let models = merge_preferred_and_discovered_models(preferred, discovered);
882→
883→            // Resolve per-provider tool_mode from config (defaults to Auto).
884→            let config_tool_mode = config
885→                .get(def.config_name)
886→                .map(|e| e.tool_mode)
887→                .unwrap_or_default();
888→
889→            // For Ollama, probe each model's family info to decide native vs text
890→            // tool calling. For non-Ollama, just pass through the config tool mode.
891→            let is_ollama = def.config_name == "ollama";
892→
893→            // Batch-probe Ollama models for family metadata (best-effort, 3s timeout).
894→            let ollama_probes: HashMap<String, OllamaShowResponse> = if is_ollama {
895→                probe_ollama_models_batch(&base_url, &models)
896→            } else {
897→                HashMap::new()
898→            };
899→

898→            };
899→
900→            for model in models {
901→                let caps = model
902→                    .capabilities
903→                    .unwrap_or_else(|| ModelCapabilities::infer(&model.id));
904→                let (model_id, display_name, created_at, recommended) = (
905→                    model.id,
906→                    model.display_name,
907→                    model.created_at,
908→                    model.recommended,
909→                );
910→                if self.has_provider_model(&provider_label, &model_id) {
911→                    continue;
912→                }
913→
914→                // Determine effective tool mode for this model.
915→                let effective_tool_mode = if is_ollama {
