917→                        config_tool_mode,
918→                        &model_id,
919→                        ollama_probes.get(&model_id),
920→                    )
921→                } else if !matches!(config_tool_mode, moltis_config::ToolMode::Auto) {
922→                    config_tool_mode
923→                } else {
924→                    // Non-Ollama providers: let OpenAiProvider use its default logic.
925→                    moltis_config::ToolMode::Auto
926→                };
927→
928→                let mut oai = openai::OpenAiProvider::new_with_name(
929→                    key.clone(),
930→                    model_id.clone(),
931→                    base_url.clone(),
932→                    provider_label.clone(),
