 68→// ── System prompt handling ───────────────────────────────────────────────────
 69→
 70→/// System prompt must reach the model (Fireworks uses standard role: "system").
 71→#[tokio::test]
 72→#[ignore]
 73→async fn system_prompt_is_received_non_streaming() {
 74→    let p = make_provider(TEST_MODEL);
 75→    let keyword = "DRAGONFRUIT";
 76→    let messages = vec![
 77→        ChatMessage::system(format!(
 78→            "You MUST include the exact word \"{keyword}\" in every response, no matter what the user asks."
 79→        )),
 80→        ChatMessage::user("What is 2+2?"),
 81→    ];
 82→
 83→    let response = p
 84→        .complete(&messages, &[])
 85→        .await
 86→        .expect("non-streaming completion should succeed");
 87→
 88→    let text = response.text.expect("response must contain text");
 89→    assert!(
 90→        text.to_lowercase().contains(&keyword.to_lowercase()),
 91→        "system prompt was not received by model: response = {text:?}"
 92→    );
 93→    assert!(
 94→        response.usage.input_tokens > 0,
 95→        "should report input tokens"
 96→    );
 97→    assert!(
 98→        response.usage.output_tokens > 0,
 99→        "should report output tokens"
100→    );
101→}
102→
103→/// Streaming variant of the system prompt test.
104→#[tokio::test]
105→#[ignore]
106→async fn system_prompt_is_received_streaming() {
107→    let p = make_provider(TEST_MODEL);
108→    let keyword = "STARFRUIT";
109→    let messages = vec![
110→        ChatMessage::system(format!(
111→            "You MUST include the exact word \"{keyword}\" in every response, no matter what the user asks."
112→        )),
113→        ChatMessage::user("What is 3+3?"),
114→    ];
115→
116→    let mut stream = p.stream_with_tools(messages, vec![]);
117→    let mut full_text = String::new();
118→    let mut saw_done = false;
119→
120→    while let Some(event) = stream.next().await {
121→        match event {
122→            StreamEvent::Delta(chunk) => full_text.push_str(&chunk),
123→            StreamEvent::Done(usage) => {
124→                saw_done = true;
125→                assert!(usage.input_tokens > 0, "should report input tokens");
126→                assert!(usage.output_tokens > 0, "should report output tokens");
127→                break;
128→            },
129→            StreamEvent::Error(err) => panic!("stream error: {err}"),
130→            _ => {},
131→        }
132→    }
133→
134→    assert!(saw_done, "stream must emit Done event");
135→    assert!(
136→        full_text.to_lowercase().contains(&keyword.to_lowercase()),
137→        "system prompt was not received by model: response = {full_text:?}"
138→    );
139→}
