// ── Model catalog validation ─────────────────────────────────────────────────

/// Probe each model in our catalog and report which ones are alive.
#[tokio::test]
#[ignore]
async fn catalog_models_are_live() {
    let mut alive = Vec::new();
    let mut dead = Vec::new();

    for &model_id in KNOWN_MODELS {
        let p = make_provider(model_id);
        match p.probe().await {
            Ok(()) => alive.push(model_id),
            Err(e) => dead.push((model_id, e.to_string())),
        }
    }

    eprintln!("\n=== Fireworks Model Catalog Health ===");
    eprintln!("Alive ({}):", alive.len());
    for m in &alive {
        eprintln!("  OK {m}");
    }
    if !dead.is_empty() {
        eprintln!("Dead ({}):", dead.len());
        for (m, err) in &dead {
            eprintln!("  DEAD {m}: {err}");
        }
    }
    eprintln!("=====================================\n");

    assert!(
        alive.contains(&TEST_MODEL),
        "{TEST_MODEL} should be reachable"
    );
}

// ── Fire Pass router: Kimi K2.5 Turbo (issue #810) ──────────────────────────

const KIMI_ROUTER_MODEL: &str = "accounts/fireworks/routers/kimi-k2p5-turbo";

/// Basic completion via Fireworks Fire Pass router to Kimi K2.5 must succeed.
/// Regression test for issue #810 where strict mode schemas caused 400 errors.
#[tokio::test]
#[ignore]
async fn kimi_router_basic_completion() {
    let p = make_provider(KIMI_ROUTER_MODEL);
    let messages = vec![ChatMessage::user(
        "What is 2+2? Answer with just the number.",
